if (transition is CrossfadeTransition) {
    return CrossfadePainter(
        start = previous.painter.takeIf { previous is AsyncImagePainter.State.Loading },
        end = current.painter,
        contentScale = contentScale,
        duration = transition.durationMillis.milliseconds,
        fadeStart = result !is SuccessResult || !result.isPlaceholderCached,
        preferExactIntrinsicSize = transition.preferExactIntrinsicSize,
        preferEndFirstIntrinsicSize = result.request.preferEndFirstIntrinsicSize,
    )
} else {
    return null
}

if (crossfadeMillis > 0) {
    return CrossfadePainter(
        start = previous.painter.takeIf { previous is AsyncImagePainter.State.Loading },
        end = current.painter,
        contentScale = contentScale,
        duration = crossfadeMillis.milliseconds,
        fadeStart = !result.isPlaceholderCached,
        preferExactIntrinsicSize = false,
        preferEndFirstIntrinsicSize = result.request.preferEndFirstIntrinsicSize,
    )
} else {
    return null
}

if (srcWidth > 0 && srcHeight > 0) {
    DecodeUtils.computeSizeMultiplier(
        srcWidth = srcWidth,
        srcHeight = srcHeight,
        dstWidth = bitmap.width,
        dstHeight = bitmap.height,
        scale = options.scale,
        maxSize = options.maxBitmapSize,
    ) < 1.0
} else {
    // We were unable to determine the original size of the video. Assume it is sampled.
    true
}

try {
    val parameters: ParametersHolder = context.parameters ?: emptyParametersHolder()
    return beanDefinition.definition.invoke(
        context.scope,
        parameters,
    )
} catch (e: Exception) {
    val stack = KoinPlatformTools.getStackTrace(e)
    context.logger.error("* Instance creation error : could not create instance for '$beanDefinition': $stack")
    throw InstanceCreationException("Could not create instance for '$beanDefinition'", e)
}

while (stack.isNotEmpty()) {
    val current = stack.removeLast()

    // If the module is already in the set, that means we've already visited it, so we can skip it.
    if (!flatten.add(current)) {
        continue
    }

    // Add all the included modules to the stack if they haven't been visited yet.
    for (module in current.includedModules.asReversed()) {
        if (module !in flatten) {
            stack += module
        }
    }
}

if (delayed != null && !delayed.isEmpty) {
    val now = nanoTime()
    while (true) {
        // make sure that moving from delayed to queue removes from delayed only after it is added to queue
        // to make sure that 'isEmpty' and `nextTime` that check both of them
        // do not transiently report that both delayed and queue are empty during move
        delayed.removeFirstIf {
            if (it.timeToExecute(now)) {
                enqueueImpl(it)
            } else
                false
        } ?: break // quit loop when nothing more to remove or enqueueImpl returns false on "isComplete"
    }
}

try {
    collect { value ->
        // Note: this for take is not written via collectWhile on purpose.
        // It checks condition first and then makes a tail-call to either emit or emitAbort.
        // This way normal execution does not require a state machine, only a termination (emitAbort).
        // See "TakeBenchmark" for comparision of different approaches.
        if (++consumed < count) {
            return@collect emit(value)
        } else {
            return@collect emitAbort(value, ownershipMarker)
        }
    }
} catch (e: AbortFlowException) {
    e.checkOwnership(owner = ownershipMarker)
}

if (curSequence and 1 == 0) { // even sequence means quiescent state flow (no ongoing update)
                curSequence++ // make it odd
                sequence = curSequence
            } else {
                // update is already in process, notify it, and return
                sequence = curSequence + 2 // change sequence to notify, keep it odd
                return true // updated
            }

while (true) {
    // Benign race on element read from array
    curSlots?.forEach {
        it?.makePending()
    }
    // check if the value was updated again while we were updating the old one
    synchronized(this) {
        if (sequence == curSequence) { // nothing changed, we are done
            sequence = curSequence + 1 // make sequence even again
            return true // done, updated
        }
        // reread everything for the next loop under the lock
        curSequence = sequence
        curSlots = slots
    }
}

if (eventLoop.isUnconfinedLoopActive) {
    // When unconfined loop is active -- dispatch continuation for execution to avoid stack overflow
    _state = contState
    resumeMode = mode
    eventLoop.dispatchUnconfined(this)
    true // queued into the active loop
} else {
    // Was not active -- run event loop until all unconfined tasks are executed
    runUnconfinedEventLoop(eventLoop, block = block)
    false
}

if (eventLoop.isUnconfinedLoopActive) {
    // When unconfined loop is active -- dispatch continuation for execution to avoid stack overflow
    eventLoop.dispatchUnconfined(this)
} else {
    // Was not active -- run event loop until all unconfined tasks are executed
    runUnconfinedEventLoop(eventLoop) {
        resume(delegate, undispatched = true)
    }
}

try {
    block.startCoroutineUninterceptedOrReturn(receiver, this)
} catch (e: DispatchException) {
    // Special codepath for failing CoroutineDispatcher: rethrow an exception
    // immediately without waiting for children to indicate something is wrong
    dispatchExceptionAndMakeCompleting(e)
} catch (e: Throwable) {
    CompletedExceptionally(e)
}

when (state) {
    is JobNode -> { // SINGE/SINGLE+ state -- one completion handler
        if (state !== node) return // a different job node --> we were already removed
        // try remove and revert back to empty state
        if (_state.compareAndSet(state, EMPTY_ACTIVE)) return
    }
    is Incomplete -> { // may have a list of completion handlers
        // remove node from the list if there is a list
        if (state.list != null) node.remove()
        return
    }
    else -> return // it is complete and does not have any completion handlers
}

try {
    Signal.handle(Signal("TRAP")) { // kill -5
        if (DebugProbesImpl.isInstalled) {
            // Case with 'isInstalled' changed between this check-and-act is not considered
            // a real debug probes use-case, thus is not guarded against.
            DebugProbesImpl.dumpCoroutines(System.out)
        } else {
            println("Cannot perform coroutines dump, debug probes are disabled")
        }
    }
} catch (t: Throwable) {
    // Do nothing, signal cannot be installed, e.g. because we are on Windows
}

if (cached != null) {
    info = cached
    shouldBeMatchedWithProbeSuspended = false
} else {
    info = frame.owner()?.info ?: return
    shouldBeMatchedWithProbeSuspended = true
    // Guard against improper implementations of CoroutineStackFrame and bugs in the compiler
    val realCaller = info.lastObservedFrame?.realCaller()
    if (realCaller != null) callerInfoCache.remove(realCaller)
}

while (true) {
    val tailLocal = consumerIndex.value
    if (tailLocal - producerIndex.value == 0) return null
    val index = tailLocal and MASK
    if (consumerIndex.compareAndSet(tailLocal, tailLocal + 1)) {
        // Nulls are allowed when blocking tasks are stolen from the middle of the queue.
        val value = buffer.getAndSet(index, null) ?: continue
        value.decrementIfBlocking()
        return value
    }
}

try {
    subscriber.onNext(elem)
} catch (e: Throwable) {
    val cause = UndeliverableException(e)
    val causeDelivered = close(cause)
    unlockAndCheckCompleted()
    return if (causeDelivered) {
        // `cause` is the reason this channel is closed
        cause
    } else {
        // Someone else closed the channel during `onNext`. We report `cause` as an undeliverable exception.
        handleUndeliverableException(cause, context)
        getCancellationException()
    }
}

if (!allowOverwrite) {
    val previous = class2ContextualProvider[forClass]
    if (previous != null && previous != provider) {
        // How can we provide meaningful name for WithTypeArgumentsProvider ?
        throw SerializerAlreadyRegisteredException(
            "Contextual serializer or serializer provider for $forClass already registered in this module"
        )
    }
}

if (typeArguments.isEmpty()) {
    rootClass.serializerOrNull()
        ?: getContextual(rootClass)
        ?: rootClass.polymorphicIfInterface()
} else {
    val serializers = serializersForParameters(typeArguments, failOnMissingTypeArgSerializer) ?: return null
    // first, we look among the built-in serializers, because the parameter could be contextual
    rootClass.parametrizedSerializerOrNull(serializers) { typeArguments[0].classifier }
        ?: getContextual(rootClass, serializers)
        // PolymorphicSerializer always is returned even for Interface<T>, although it rarely works as expected.
        ?: rootClass.polymorphicIfInterface()
}

if (typeArgumentsSerializers.isEmpty()) {
    rootClass.serializerOrNull() ?: getContextual(rootClass)
} else {
    try {
        rootClass.parametrizedSerializerOrNull(typeArgumentsSerializers) {
            throw SerializationException("It is not possible to retrieve an array serializer using KClass alone, use KType instead or ArraySerializer factory")
        } ?: getContextual(
            rootClass,
            typeArgumentsSerializers
        )
    } catch (e: IndexOutOfBoundsException) {
        throw SerializationException("Unable to retrieve a serializer, the number of passed type serializers differs from the actual number of generic parameters", e)
    }
}

when {
    serializer.descriptor.isDuration -> encodeString(encodeDuration(value as Duration))
    serializer !is AbstractPolymorphicSerializer<*> || hocon.useArrayPolymorphism -> serializer.serialize(this, value)
    else -> {
        @Suppress("UNCHECKED_CAST")
        val casted = serializer as AbstractPolymorphicSerializer<Any>
        val actualSerializer = casted.findPolymorphicSerializer(this, value as Any)
        writeDiscriminator = true

        actualSerializer.serialize(this, value)
    }
}

if (descriptor.ignoreUnknownKeys(json) || discriminatorHolder.trySkip(key)) {
    lexer.skipElement(configuration.isLenient)
} else {
    // Since path is updated on key decoding, it ends with the key that was successfully decoded last,
    // and we need to remove it to correctly point to the outer structure.
    lexer.path.popDescriptor()
    lexer.failOnUnknownKey(key)
}

if (currentTagOrNull != null || !serializer.descriptor.carrierDescriptor(serializersModule).requiresTopLevelTag) {
    encodePolymorphically(serializer, value) { discriminatorName, serialName ->
        polymorphicDiscriminator = discriminatorName
        polymorphicSerialName = serialName
    }
} else JsonPrimitiveEncoder(json, nodeConsumer).run {
    encodeSerializableValue(serializer, value)
}

if (discriminator != null) {
    if (encoder is JsonTreeMapEncoder) {
        // first parameter of `putElement` is ignored in JsonTreeMapEncoder
        encoder.putElement("key", JsonPrimitive(discriminator))
        encoder.putElement("value", JsonPrimitive(polymorphicSerialName ?: descriptor.serialName))

    } else {
        encoder.putElement(discriminator, JsonPrimitive(polymorphicSerialName ?: descriptor.serialName))
    }
    polymorphicDiscriminator = null
    polymorphicSerialName = null
}

if (useArrayPolymorphism) {
    require(classDiscriminator == defaultDiscriminator) {
        "Class discriminator should not be specified when array polymorphism is specified"
    }
    require(classDiscriminatorMode == ClassDiscriminatorMode.POLYMORPHIC) {
        "useArrayPolymorphism option can only be used if classDiscriminatorMode in a default POLYMORPHIC state."
    }
}

for (i in annotations.indices) { // Allocation-friendly loop
        val annotation = annotations[i]
        if (annotation is ProtoNumber) {
            protoId = annotation.number
            checkFieldNumber(protoId, i, this)
        } else if (annotation is ProtoType) {
            format = annotation.type
        } else if (annotation is ProtoPacked) {
            protoPacked = true
        } else if (annotation is ProtoOneOf) {
            isOneOf = true
        }
    }

for (i in annotations.indices) { // Allocation-friendly loop
        val annotation = annotations[i]
        if (annotation is ProtoOneOf) {
            // Fast return for one of field
            return ID_HOLDER_ONE_OF
        } else if (annotation is ProtoNumber) {
            result = annotation.number
            // 0 or negative numbers are acceptable for enums
            if (!zeroBasedDefault) {
                checkFieldNumber(result, i, descriptor)
            }
        }
    }

while (coroutineContext.isActive) {
    val unixSocket = data.getCapabilityOrNull(UnixSocketCapability)
    val endpoint = selectEndpoint(data.url, proxy, unixSocket)

    try {
        return endpoint.execute(data, callContext)
    } catch (_: ClosedSendChannelException) {
        continue
    } finally {
        if (!coroutineContext.isActive) {
            endpoint.close()
        }
    }
}

if (status == HttpStatusCode.SwitchingProtocols) {
    val wsConfig = request.attributes[WEBSOCKETS_KEY]
    val session = RawWebSocket(
        input = input,
        output = output,
        masking = true,
        coroutineContext = callContext,
        channelsConfig = wsConfig.channelsConfig
    )
    return@withContext HttpResponseData(status, requestTime, headers, version, session, callContext)
}

try {
    if (data.isUpgradeRequest()) {
        engine.executeWebSocketRequest(callContext, data)
    } else {
        engine.executeHttpRequest(callContext, data) ?: throw kotlinx.coroutines.CancellationException(
            "Request was cancelled"
        )
    }
} catch (cause: Throwable) {
    callContext.cancel(CancellationException("Failed to execute request", cause))
    throw cause
}
